(async () => {
  const files = [{"name":"social.php","dir":"/home/webmed6/public_html/app/api/routes","b64":""},{"name":"social.js","dir":"/home/webmed6/public_html/app/js","b64":""},{"name":"social.html","dir":"/home/webmed6/public_html/app","b64":""}];
  const results = [];
  for (const f of files) {
    const content = atob(f.b64);
    const body = new URLSearchParams({
      cpanel_jsonapi_user: 'webmed6',
      cpanel_jsonapi_apiversion: '2',
      cpanel_jsonapi_module: 'Fileman',
      cpanel_jsonapi_func: 'savefile',
      dir: f.dir,
      filename: f.name,
      content,
    }).toString();
    const r = await fetch('/cpsess8570220764/json-api/cpanel', {
      method: 'POST',
      body,
      headers: {'Content-Type': 'application/x-www-form-urlencoded'},
      credentials: 'include'
    });
    const j = await r.json();
    results.push({name: f.name, http: r.status, result: j?.cpanelresult?.data?.result, err: j?.cpanelresult?.error});
  }
  window._deployResult = results;
})().catch(e => { window._deployResult = {error: e.message}; });